import React from "react";
import MessageForm from "./MessageForm";

const formatTime = (dateString) => new Date(dateString).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
const reactionChoices = ["👍", "❤️", "😂", "🔥", "😮"];
const API_URL = process.env.REACT_APP_API_URL || "";
const API_BASE = API_URL.replace(/\/api\/?$/, "");

const toAttachmentUrl = (url) => {
  if (!url) return "";
  if (url.startsWith("http://") || url.startsWith("https://")) return url;
  return `${API_BASE}${url}`;
};

const isImage = (mimeType = "") => mimeType.startsWith("image/");

export default function ChatInterface({ activeRoom, messages, roomUsers, currentUser, onSendMessage, onToggleReaction, onKickMember, onDeleteRoom }) {
  if (!activeRoom) {
    return <section className="chat-interface glass empty-chat"><h3>Select a room to start chatting</h3><p>Join a room from the left panel or create a new one.</p></section>;
  }

  const creatorId = activeRoom.createdBy?._id || activeRoom.createdBy?.id || activeRoom.createdBy;
  const isAdmin = activeRoom.admins?.some((admin) => (admin._id || admin.id) === currentUser?.id) || creatorId === currentUser?.id;

  return (
    <section className="chat-interface glass">
      <header className="chat-head">
        <div><h3>#{activeRoom.name}</h3><p>{activeRoom.description || "No room description yet"}</p></div>
        <div className="room-user-chips">
          {roomUsers.map((u) => {
            const userId = u.id || u._id;
            return (
              <span key={userId} className="chip">
                {u.username}
                {isAdmin && userId !== currentUser?.id && userId !== creatorId ? (
                  <button type="button" className="chip-kick-btn" onClick={() => onKickMember(activeRoom._id, userId)}>Kick</button>
                ) : null}
              </span>
            );
          })}
          {isAdmin ? <button type="button" className="danger-btn delete-room-btn" onClick={() => onDeleteRoom(activeRoom._id)}>Delete Room</button> : null}
        </div>
      </header>

      <div className="message-list">
        {messages.map((message) => {
          const ownMessage = (message.user?._id || message.user?.id) === currentUser?.id;
          if (message.system) {
            return <div className="system-message" key={message._id || message.createdAt + message.content}><span>{message.content}</span><small>{formatTime(message.createdAt)}</small></div>;
          }
          return (
            <article key={message._id || message.createdAt + message.content} className={ownMessage ? "msg own" : "msg"}>
              <div className="msg-meta"><strong>{message.user?.username || "Unknown"}</strong><small>{formatTime(message.createdAt)}</small></div>
              {message.content ? <p>{message.content}</p> : null}
              {message.attachments?.length ? (
                <div className="msg-attachments">
                  {message.attachments.map((file) => (
                    <a key={`${file.url}-${file.fileName}`} href={toAttachmentUrl(file.url)} target="_blank" rel="noreferrer" className="msg-file-link">
                      {isImage(file.mimeType) ? <img src={toAttachmentUrl(file.url)} alt={file.fileName} className="msg-image" /> : null}
                      <span>{file.fileName}</span>
                    </a>
                  ))}
                </div>
              ) : null}
              <div className="reactions-row">
                {reactionChoices.map((emoji) => {
                  const reaction = message.reactions?.find((entry) => entry.emoji === emoji);
                  const count = reaction?.users?.length || 0;
                  const reacted = reaction?.users?.some((u) => (u.id || u._id) === currentUser?.id);
                  return (
                    <button key={emoji} type="button" className={reacted ? "reaction-btn active" : "reaction-btn"} onClick={() => onToggleReaction(message._id, emoji)}>
                      {emoji} {count ? count : ""}
                    </button>
                  );
                })}
              </div>
            </article>
          );
        })}
      </div>

      <MessageForm onSend={onSendMessage} />
    </section>
  );
}
